//vip.opstream12.com/share/577bacbdbbb574034730d06aa6ab049c","link_m3u8":"https://vip.opstream12.com/20220426/12937_e205d616/index.m3u8"}]}],"time":"45 phút / tập","description":"<p>Bộ phim \"Quân sư liên minh - Phần 1\" xoay quanh cuộc đời Tư Mã Ý, một chính trị, một quân sư nổi lẫy lừng thời Tam Quốc. Sau khi con trai Tào Tháo là Tào Phi lật đổ nhà Hán, lập nên nước Nguỵ, thì lãnh thổ Trung Nguyên từ đó đã dần dần hình thành nên thế chân vạc. Tuy nhiên, với tài năng mưu lược hơn người, và có Trương Xuân Hoa túc trí thao lược ở bên, Tư Mã Ý đã đặt những nền móng đầu tiên trong việc lật đổ nhà Thục của họ Tào, lập ra nhà Tây Tấn, tiêu diệt nhà Ngô và thống nhất lãnh thổ đã bị phân cắt sâu sắc của Trung Nguyên thành một mối....</p>","tmdb":{"type":"tv","id":"72311","season":1,"vote_average":8.3,"vote_count":25},"modified":"2023-06-12T14:22:02.000Z"},{"id":"62680f4dfa02df5563cb268b","_id":"62680f4dfa02df5563cb268b","title":"Bạn Tốt","origin_name":"Ajami","slug":"ban-tot","year":2009,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"},{"id":"620a2249e0fc277084dfd2e5","name":"Hình Sự","slug":"hinh-su"}],"country":[{"id":"620e0e8fd9648f114cde77f7","name":"Đức","slug":"duc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"ban-tot-ajami","link_embed":"https://vip.opstream12.com/share/c05c903e3d997added79518f0e850026","link_m3u8":"https://vip.opstream12.com/20220426/12821_bc6045a3/index.m3u8"}]}],"time":"Đang cập nhật","description":"<p>Bộ phim Ajami, được đặt tên theo khu vực cận Jaffa phía nam Tel Aviv nơi bộ phim diễn ra, theo chân những nhân vật riêng biệt bị thị tộc, tôn giáo và sắc tộc chia rẽ dữ dội khi họ vật lộn nhau một cách oan nghiệt trong thế giới ngầm đầy tội ác của Ajami.</p>","tmdb":{"type":"movie","id":"24424","season":null,"vote_average":7.023,"vote_count":87},"modified":"2023-08-27T10:45:49.000Z"},{"id":"62680f64fa02df5563cb26a2","_id":"62680f64fa02df5563cb26a2","title":"Bí Mật Ánh Dương","origin_name":"Secret Sunshine","slug":"bi-mat-anh-duong","year":2007,"type":"single","genre":[{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a2300e0fc277084dfd6d2","name":"Hàn Quốc","slug":"han-quoc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"bi-mat-anh-duong-secret-sunshine","link_embed":"https://vip.opstream12.com/share/03ea906731be85e38d49277fa858b7a1","link_m3u8":"https://vip.opstream12.com/20220426/12822_045b08f0/index.m3u8"}]}],"time":"Đang cập nhật","description":"<p>Shin Ae và cậu con trai Jun cùng dời đến làng Miryang sinh sống. Shin Ae đã mất rất nhiều thứ, mất đi người chồng của mình và mơ ước trở thành một nhà dương cầm. Tại ngôi làng này, Shin Ae bắt đầu một cuộc sống mới bằng việc mở một lớp dạy đàn. Tại nơi đây, có một người đàn ông tên Jong Chan đã yêu Shin Ae ngay từ lần gặp đầu tiên, và anh luôn lặng lẽ giúp đỡ Shin Ae vượt qua mọi khó khăn...</p>","tmdb":{"type":"movie","id":"2015","season":null,"vote_average":7.2,"vote_count":221},"modified":"2023-08-27T10:46:04.000Z"},{"id":"62680f9efa02df5563cb26d4","_id":"62680f9efa02df5563cb26d4","title":"Cảnh Sát Người Máy 2014","origin_name":"RoboCop","slug":"canh-sat-nguoi-may-2014","year":2014,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2249e0fc277084dfd2e5","name":"Hình Sự","slug":"hinh-su"},{"id":"620a2282e0fc277084dfd435","name":"Viễn Tưởng","slug":"vien-tuong"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620a229be0fc277084dfd4dd","name":"Khoa Học","slug":"khoa-hoc"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"canh-sat-nguoi-may-2014-robocop","link_embed":"https://vip.opstream12.com/share/0b9cc53336c8d4b6e3e515fecd9b81fb","link_m3u8":"https://vip.opstream12.com/20220426/12823_203f5d1c/index.m3u8"}]}],"time":"Đang cập nhật","description":"<p>Cảnh Sát Người Máy - Robocop 2014 là một bộ phim hành động khoa học viễn tưởng của đạo diễn Mỹ José Padilha. Năm 2028, OmniCorp là một trung tâm công nghệ robot. Máy bay không người lái của trung tâm được quân đội nước ngoài sử dụng từ rất lâu nhưng lại bị pháp luật Mỹ cấm. Tuy nhiên, OmniCorp như gặp một cơ hội ngàn vàng để thâm nhập khị trường khi cảnh sát Detroit Murphy (Joel Kinnaman) bị thương nặng trong khi làm nhiệm vụ. Bằng cách chuyển đổi Murphy thành một cyborg (nửa người nửa robot). Giám đốc điều hành OmniCorp hi vọng sẽ mang hàng tỉ đô-la cho các cổ đông nhưng bọn họ quên 1 điều rằng, Vẫn còn một con người bên trong cỗ máy.</p>","tmdb":{"type":"movie","id":"97020","season":null,"vote_average":5.9,"vote_count":5682},"modified":"2023-08-27T10:38:16.000Z"},{"id":"62680fe8fa02df5563cb2704","_id":"62680fe8fa02df5563cb2704","title":"Câu Chuyện Trò Chơi","origin_name":"Toy Story","slug":"cau-chuyen-tro-choi","year":1995,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2282e0fc277084dfd435","name":"Viễn Tưởng","slug":"vien-tuong"},{"id":"620a2293e0fc277084dfd489","name":"Phiêu Lưu","slug":"phieu-luu"},{"id":"620a229be0fc277084dfd4dd","name":"Khoa Học","slug":"khoa-hoc"},{"id":"620e4c0b6ba8271c5eef05a8","name":"Gia Đình","slug":"gia-dinh"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"cau-chuyen-tro-choi-toy-story","link_embed":"https://vip.opstream12.com/share/0e3e75d3095f3746ec2531e0bf543a5c","link_m3u8":"https://vip.opstream12.com/20220426/12825_0c9f8d40/index.m3u8"}]}],"time":"Đang cập nhật","description":"<p>Câu chuyện về thế giới đồ chơi của cậu bé Andy (John Morris lồng tiếng) 6 tuổi với những cảm xúc, xung đột như thế giới của con người. Trong số vô thiên lủng các món đồ chơi của Andy, anh chàng cao bồi gỗ Woody (Tom Hanks lồng tiếng) được yêu quý hơn cả trong một thời gian dài. Nhưng từ khi có sự xuất hiện của “cảnh sát vũ trụ” Buzz Lightyear (Tim Allen lồng tiếng), vị trí của Woody dường như lung lay, nhưng anh chàng kiên quyết không cam chịu sự thay đổi này. Khi Andy đi vắng, cuộc sống của những món đồ chơi trở nên sôi động hơn bao giờ hết. Đặc biệt là sự xô xát giữa Woody và Buzz Lightyear biến thành một cuộc chiến thực sự đến nỗi Buzz vô tình bị rơi ra khỏi cửa sổ. Bị cộng đồng đồ chơi kết tội là đã giết Buzz vì ghen tuông, Woody phải rời khỏi nhà lên đường tìm kiếm anh bạn Buzz. Cả hai gặp đầy rẫy những rắc rối trên đường trở về nhà. Nguy hiểm nhất đối với cả Buzz và Woody là việc phải đối đầu với anh bạn hàng xóm Sid (Erik von Detten) tàn ác luôn tìm trò tiêu khiển bằng cách vặt tay chân của các món đồ chơi rồi lắp ráp lại như cũ. Kè kè bên cạnh Sid còn có chú chó Scud đánh hơi rất thính. Bên nhau trong những lúc tưởng như cái chết đang lơ lửng trên đầu, cả hai mới nhận ra rằng chỉ có tình bạn, sự thông cảm và chia sẻ lẫn nhau mới giúp chúng thoát chết.</p>","tmdb":{"type":"movie","id":"862","season":null,"vote_average":7.97,"vote_count":19291},"modified":"2023-08-27T10:38:31.000Z"},{"id":"6268101ffa02df5563cb272f","_id":"6268